// 시/도 슬러그로 조회
export const getSido = (slug: string) => REGIONS.find((r) => r.slug === slug);

// 한 시/도의 전체 동을 가나다순 평탄화 (전체보기 탭용)
export const allDongOf = (sidoSlug: string) =>
  (getSido(sidoSlug)?.sigungu ?? [])
    .flatMap((sg) => sg.dong.map((d) => ({ ...d, sigungu: sg.name, sigunguSlug: sg.slug })))
    .sort((a, b) => a.name.localeCompare(b.name, "ko"));
